return ['domain'=>'magicauth','plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'nl_NL','project-id-version'=>'MagicAuth 1.0.3','pot-creation-date'=>'2026-05-22T19:10:14+00:00','po-revision-date'=>'2026-05-22','x-generator'=>'MagicAuth i18n generator','messages'=>['Passwordless WordPress sign-in via email magic link or 6-character code.'=>'Wachtwoordloos inloggen op WordPress via een magische e-maillink of een 6-tekens code.','MagicAuth by Ettic.'=>'MagicAuth van Ettic.','Focused, open-source WordPress plugins.'=>'Gerichte, open-source WordPress-plug-ins.','MagicAuth resources'=>'MagicAuth-bronnen','Docs'=>'Documentatie','Support'=>'Ondersteuning','Report a vulnerability'=>'Een kwetsbaarheid melden','Like MagicAuth? Leave a review and help us keep building open source.'=>'Vind je MagicAuth goed? Laat een review achter en help ons open source te blijven bouwen.','Leave a review'=>'Laat een review achter','Settings'=>'Instellingen','Discard'=>'Verwerpen','Save changes'=>'Wijzigingen opslaan','Passwordless sign-in via magic link or 6-character code. Configure how it looks, how it behaves, and how it recovers from edge cases. All on one page.'=>'Wachtwoordloos inloggen via een magische link of een 6-tekens code. Stel in hoe het eruitziet, hoe het zich gedraagt en hoe het herstelt bij randgevallen. Allemaal op één pagina.','General'=>'Algemeen','How long links live and where users land afterwards.'=>'Hoe lang links geldig blijven en waar gebruikers daarna terechtkomen.','Branding'=>'Branding','How the sign-in card looks. Settings render on the branded login screen and in transactional emails.'=>'Hoe de inlogkaart eruitziet. Deze instellingen verschijnen op het gebrande inlogscherm en in transactionele e-mails.','Agency credit'=>'Bureaucredit','Optional "Built by [Brand]" line below the sign-in card. Renders only when name, URL, and favicon are all filled.'=>'Optionele regel "Gemaakt door [Merk]" onder de inlogkaart. Verschijnt alleen als naam, URL en favicon allemaal zijn ingevuld.','Security &amp; throttling'=>'Beveiliging &amp; throttling','Recovery layers and rate-limit caps. The "Sign in with password" link is the unconditional safety net. Disable it only after site-wide password auth is already off.'=>'Herstellagen en rate-limietplafonds. De link "Inloggen met wachtwoord" is het onvoorwaardelijke vangnet. Schakel deze pas uit nadat wachtwoordauthenticatie sitebreed al is uitgeschakeld.','Diagnostics &amp; recovery'=>'Diagnose &amp; herstel','One-shot tools for debugging and unsticking the plugin. Destructive actions ask for confirmation.'=>'Eenmalige hulpmiddelen om te debuggen en de plug-in weer vlot te trekken. Destructieve acties vragen om bevestiging.','Send test email'=>'Test-e-mail versturen','One-shot diagnostic. No tokens are issued. Forces the default brand color to verify rendering.'=>'Eenmalige diagnose. Er worden geen tokens uitgegeven. Forceert de standaard merkkleur om de weergave te controleren.','Send to my account'=>'Naar mijn account sturen','Revoke all magic-links and codes'=>'Alle magische links en codes intrekken','Marks every unconsumed token consumed site-wide. Already-active sessions are not signed out.'=>'Markeert elk niet-gebruikt token sitebreed als gebruikt. Reeds actieve sessies worden niet uitgelogd.','Revoke now'=>'Nu intrekken','Reset throttle counters'=>'Throttle-tellers resetten','Deletes every magicauth_throttle_* transient. Object-cache safe.'=>'Verwijdert elke magicauth_throttle_*-transient. Veilig voor object-cache.','Reset now'=>'Nu resetten','Branded login is enabled, but your WordPress salts are still weak. Magic links each carry their own random secret so they stay safe; your session cookies and the 6-character codes are better protected once you fix the salts. See the weak-salt notice for how.'=>'Het gebrande inlogscherm staat aan, maar je WordPress-salts zijn nog steeds zwak. Elke magische link draagt zijn eigen willekeurige geheim, dus die blijven veilig; je sessiecookies en de 6-tekens codes zijn beter beschermd zodra je de salts herstelt. Zie de melding over zwakke salts voor hoe.','Sender address: that value had no usable characters, so it was reset to "login".'=>'Afzenderadres: die waarde bevatte geen bruikbare tekens en is teruggezet op "login".','Logo: selected attachment is not an image.'=>'Logo: het geselecteerde bestand is geen afbeelding.','Logo: SVG contains active content (script / event handlers / javascript:). Re-export without scripting.'=>'Logo: SVG bevat actieve inhoud (script / event-handlers / javascript:). Exporteer opnieuw zonder scripting.','Logo: only PNG, JPG, WebP, or SVG are allowed.'=>'Logo: alleen PNG, JPG, WebP of SVG zijn toegestaan.','Logo: file content does not match a supported image format.'=>'Logo: de bestandsinhoud komt niet overeen met een ondersteund afbeeldingsformaat.','Link &amp; code lifetime'=>'Levensduur van link &amp; code','Both the magic link and the typeable code share one expiry. Range 1–30 minutes.'=>'De magische link en de typbare code delen één vervaltijd. Bereik 1–30 minuten.','minutes'=>'minuten','Max link uses'=>'Max. linkgebruik','2 absorbs URL-scanner prefetch plus the user\'s click. Set to 1 for strict single-use.'=>'2 vangt prefetch door URL-scanners op plus de klik van de gebruiker. Stel in op 1 voor strikt eenmalig gebruik.','Auto (admin or home, by capability)'=>'Automatisch (beheer of home, op basis van rechten)','Site home'=>'Sitehome','Admin dashboard'=>'Beheerdashboard','Default redirect after sign-in'=>'Standaard doorverwijzing na inloggen','Where users land when no specific destination was requested.'=>'Waar gebruikers terechtkomen als er geen specifieke bestemming is opgevraagd.','Replace WordPress login screen'=>'WordPress-inlogscherm vervangen','Why is this flagged?'=>'Waarom is dit gemarkeerd?','Heads up: weak salts'=>'Let op: zwakke salts','You can turn this on now, but the salts in'=>'Je kunt dit nu inschakelen, maar de salts in','are weak — fixing them first is recommended.'=>'zijn zwak — het wordt aanbevolen die eerst te herstellen.','How to fix →'=>'Hoe te herstellen →','Intercepts wp-login.php and serves the branded MagicAuth screen. The native form stays available at ?magicauth=off as a recovery path.'=>'Onderschept wp-login.php en toont het gebrande MagicAuth-scherm. Het oorspronkelijke formulier blijft beschikbaar via ?magicauth=off als herstelpad.','Hide language switcher'=>'Taalwisselaar verbergen','WordPress adds a language selector to the login screen when extra languages are installed. MagicAuth places it under the card. Turn this on to hide it on the branded screen; the recovery login at ?magicauth=off keeps it.'=>'WordPress voegt een taalkeuze toe aan het inlogscherm wanneer er extra talen zijn geïnstalleerd. MagicAuth plaatst die onder de kaart. Schakel dit in om de taalkeuze op het gebrande scherm te verbergen; de herstel-login op ?magicauth=off behoudt die.','Company name'=>'Bedrijfsnaam','Your short business name. No taglines, slogans, or separators.'=>'Je korte bedrijfsnaam. Geen taglines, slogans of scheidingstekens.','Sender email address'=>'Afzender-e-mailadres','The address sign-in emails are sent from. Only the part before the @ is editable — it stays on your own domain so messages pass spam checks (SPF/DKIM/DMARC) instead of being flagged as forged. Letters, digits, and . _ - + only.'=>'Het adres waarvandaan inlogmails worden verstuurd. Alleen het deel vóór de @ is bewerkbaar — het blijft op je eigen domein, zodat berichten de spamcontroles (SPF/DKIM/DMARC) doorstaan in plaats van als vervalst te worden gemarkeerd. Alleen letters, cijfers en . _ - +.','PNG, JPG, or WebP. Existing SVG attachments may also be selected. Capped at 48px height on the sign-in card.'=>'PNG, JPG of WebP. Bestaande SVG-bijlagen kunnen ook worden geselecteerd. Beperkt tot 48px hoogte op de inlogkaart.','Brand color'=>'Merkkleur','Auto-derives readable button text via YIQ luminance. Current contrast:'=>'Leidt automatisch leesbare knoptekst af via YIQ-luminantie. Huidig contrast:','Color picker'=>'Kleurkiezer','Brand name'=>'Merknaam','Shown bold in the credit line.'=>'Vetgedrukt weergegeven in de creditregel.','Brand URL'=>'Merk-URL','Opens in a new tab. Must start with http:// or https://.'=>'Opent in een nieuw tabblad. Moet beginnen met http:// of https://.','Brand favicon'=>'Merk-favicon','Square 32×32 or larger. PNG, JPG, WebP, or SVG.'=>'Vierkant 32×32 of groter. PNG, JPG, WebP of SVG.','Credit label'=>'Creditlabel','Text shown before the brand name. Leave blank for the default ("Built by").'=>'Tekst die vóór de merknaam wordt getoond. Laat leeg voor de standaard ("Gemaakt door").','Built by'=>'Gemaakt door','"Sign in with password" link'=>'Link "Inloggen met wachtwoord"','Always-visible recovery link on every form. Only disable this if you have already disabled WordPress password authentication site-wide.'=>'Altijd zichtbare herstellink op elk formulier. Schakel dit alleen uit als je WordPress-wachtwoordauthenticatie al sitebreed hebt uitgeschakeld.','Per-IP window (hours)'=>'Venster per IP (uren)','Per-IP max requests'=>'Max. verzoeken per IP','Per-IP code window (hours)'=>'Codevenster per IP (uren)','Per-IP max code attempts'=>'Max. codepogingen per IP','Per-email cooldown'=>'Afkoeltijd per e-mail','Seconds between consecutive link requests for the same email. 0 disables. Default 60. Replaced the per-email hard cap in v1.3.7. That cap was a DoS primitive any IP could weaponize against any victim email.'=>'Seconden tussen opeenvolgende linkverzoeken voor hetzelfde e-mailadres. 0 schakelt het uit. Standaard 60. Verving de harde limiet per e-mail in v1.3.7. Die limiet was een DoS-primitief dat elk IP tegen elk slachtoffer-e-mailadres kon inzetten.','seconds'=>'seconden','Replace'=>'Vervangen','Remove'=>'Verwijderen','You are not allowed to do this.'=>'Je mag dit niet doen.','%d outstanding token revoked.'=>'%d openstaand token ingetrokken.' . "\0" . '%d openstaande tokens ingetrokken.','%d throttle counter cleared.'=>'%d throttle-teller gewist.' . "\0" . '%d throttle-tellers gewist.','Per-user controls'=>'Instellingen per gebruiker','Disable magic-link sign-in for this user'=>'Inloggen met magische link uitschakelen voor deze gebruiker','Saving with this checked invalidates all outstanding sign-in links for this user immediately.'=>'Opslaan met dit aangevinkt maakt alle openstaande inloglinks voor deze gebruiker direct ongeldig.','Magic-link actions'=>'Acties voor magische link','Create magic-link'=>'Magische link aanmaken','Send link to user'=>'Link naar gebruiker sturen','Reset all magic-links'=>'Alle magische links resetten','Cleared on next page load. Copy now.'=>'Wordt gewist bij de volgende paginalading. Kopieer nu.','Could not issue link.'=>'Kon geen link uitgeven.','Link created. Copy the URL now. It disappears on reload.'=>'Link aangemaakt. Kopieer de URL nu. Hij verdwijnt bij herladen.','wp_mail returned false. Check the server\'s mail configuration.'=>'wp_mail gaf false terug. Controleer de mailconfiguratie van de server.','Link sent.'=>'Link verstuurd.','%d outstanding link reset.'=>'%d openstaande link gereset.' . "\0" . '%d openstaande links gereset.','Missing user.'=>'Gebruiker ontbreekt.','User not found.'=>'Gebruiker niet gevonden.','This sign-in link is for a different account.'=>'Deze inloglink is voor een ander account.','Sign out first if you need to switch accounts.'=>'Log eerst uit als je van account wilt wisselen.','Back to site'=>'Terug naar de site','If an account exists for that email, we sent a sign-in link.'=>'Als er een account bestaat voor dat e-mailadres, hebben we een inloglink verstuurd.','MagicAuth sign-in tokens'=>'MagicAuth-inlogtokens','Selector'=>'Selector','Issued'=>'Uitgegeven','Expires'=>'Verloopt','Consumed'=>'Gebruikt','not yet'=>'nog niet','%1$s is your %2$s-code'=>'%1$s is je %2$s-code','About your sign-in request for %s'=>'Over je inlogverzoek voor %s','Sign in'=>'Inloggen','You\'re already signed in as %s.'=>'Je bent al ingelogd als %s.','Sign out'=>'Uitloggen','That reset link has expired or already been used. Request a new one below.'=>'Die herstellink is verlopen of al gebruikt. Vraag hieronder een nieuwe aan.','That sign-in link has expired or already been used. Request a new code or link below.'=>'Die inloglink is verlopen of al gebruikt. Vraag hieronder een nieuwe code of link aan.','If an account exists for that email, we sent a password reset link.'=>'Als er een account bestaat voor dat e-mailadres, hebben we een link voor wachtwoordherstel verstuurd.','Email sent. Check your mail app.'=>'E-mail verstuurd. Controleer je mailapp.','That code is invalid or has expired. Try again, or request a new code.'=>'Die code is ongeldig of verlopen. Probeer het opnieuw of vraag een nieuwe code aan.','Sign-in failed. Check your username and password, or use a magic link instead.'=>'Inloggen mislukt. Controleer je gebruikersnaam en wachtwoord, of gebruik anders een magische link.','Could not set a new password. Make sure both fields match and try again.'=>'Kon geen nieuw wachtwoord instellen. Zorg dat beide velden overeenkomen en probeer het opnieuw.','Please wait %d seconds before requesting another link for this email.'=>'Wacht %d seconden voordat je opnieuw een link aanvraagt voor dit e-mailadres.','Please wait a moment before requesting another link for this email.'=>'Wacht even voordat je opnieuw een link aanvraagt voor dit e-mailadres.','Too many sign-in requests from your network. Please try again later, or sign in with a password.'=>'Te veel inlogverzoeken vanaf je netwerk. Probeer het later opnieuw of log in met een wachtwoord.','Too many code attempts from your network. Please request a new sign-in link.'=>'Te veel codepogingen vanaf je netwerk. Vraag een nieuwe inloglink aan.','Too many sign-in attempts. Please wait a few minutes before trying again.'=>'Te veel inlogpogingen. Wacht een paar minuten voordat je het opnieuw probeert.','Too many password-reset requests. Please wait an hour before trying again.'=>'Te veel verzoeken voor wachtwoordherstel. Wacht een uur voordat je het opnieuw probeert.','Too many incorrect codes for this link. Please request a new sign-in link.'=>'Te veel onjuiste codes voor deze link. Vraag een nieuwe inloglink aan.','Dismiss'=>'Sluiten','MagicAuth: response-flush helper unavailable.'=>'MagicAuth: hulpfunctie voor response-flush niet beschikbaar.','Your PHP runtime does not provide fastcgi_finish_request(). MagicAuth cannot defer email sending until after the response, so SMTP latency may leak whether an account exists. Switch to PHP-FPM (or LiteSpeed) for full timing parity.'=>'Je PHP-runtime biedt geen fastcgi_finish_request(). MagicAuth kan het versturen van e-mail niet uitstellen tot na de respons, waardoor SMTP-latentie kan verraden of een account bestaat. Stap over naar PHP-FPM (of LiteSpeed) voor volledige timing-pariteit.','MagicAuth: weak WordPress salts detected.'=>'MagicAuth: zwakke WordPress-salts gedetecteerd.','Your security keys still hold placeholder or empty values, so token and session secrets are not unique to this site. Your magic links stay safe (each carries its own random secret), but fixing this is recommended — especially before turning on the branded login replacement.'=>'Je beveiligingssleutels bevatten nog placeholder- of lege waarden, dus token- en sessiegeheimen zijn niet uniek voor deze site. Je magische links blijven veilig (elke link draagt zijn eigen willekeurige geheim), maar dit herstellen wordt aanbevolen — vooral voordat je de gebrande inlogvervanging inschakelt.','Learn how to fix this'=>'Lees hoe je dit herstelt','MagicAuth login activity'=>'MagicAuth-inlogactiviteit','Built by %s'=>'Gemaakt door %s','A sign-in code was just requested for your account at %s.'=>'Er is zojuist een inlogcode aangevraagd voor je account bij %s.','Magic link and code sign-in is currently turned off for your account, so no code was sent. This is a setting managed by your site administrator and is often part of routine account changes.'=>'Inloggen met magische link en code is momenteel uitgeschakeld voor je account, dus er is geen code verstuurd. Dit is een instelling die door je sitebeheerder wordt beheerd en maakt vaak deel uit van routinematige accountwijzigingen.','You may still be able to sign in with your password through the regular sign-in screen. If you are not sure whether your account should have access, please contact your site administrator.'=>'Je kunt mogelijk nog steeds inloggen met je wachtwoord via het gewone inlogscherm. Als je niet zeker weet of je account toegang hoort te hebben, neem dan contact op met je sitebeheerder.','If you have questions about your account access, please contact your site administrator.'=>'Heb je vragen over de toegang tot je account, neem dan contact op met je sitebeheerder.','If you did not request a sign-in code, you can ignore this message. No further action is needed.'=>'Heb je geen inlogcode aangevraagd, dan kun je dit bericht negeren. Er is geen verdere actie nodig.','Sign in to %s'=>'Inloggen bij %s','Use the code below or open the sign-in link. Both expire in %d minutes.'=>'Gebruik de onderstaande code of open de inloglink. Beide verlopen over %d minuten.','Sign-in code:'=>'Inlogcode:','Sign-in link:'=>'Inloglink:','If you didn\'t request this, you can safely ignore this email.'=>'Heb je dit niet aangevraagd, dan kun je deze e-mail veilig negeren.','(This is a test send from the MagicAuth diagnostics screen.)'=>'(Dit is een testverzending vanaf het MagicAuth-diagnosescherm.)','Use the code below or click the button to sign in. Both expire in %d minutes.'=>'Gebruik de onderstaande code of klik op de knop om in te loggen. Beide verlopen over %d minuten.','Test send'=>'Testverzending','Check your email'=>'Controleer je e-mail','Reset your password'=>'Stel je wachtwoord opnieuw in','Set a new password'=>'Stel een nieuw wachtwoord in','Enter the verification code we sent to %s.'=>'Voer de verificatiecode in die we naar %s hebben gestuurd.','Enter the 6-character code we just emailed you.'=>'Voer de 6-tekens code in die we je zojuist hebben gemaild.','Enter your username or email and we will send a link to set a new password.'=>'Voer je gebruikersnaam of e-mailadres in en we sturen een link om een nieuw wachtwoord in te stellen.','Choose a strong password. You will be signed in once it is saved.'=>'Kies een sterk wachtwoord. Je wordt ingelogd zodra het is opgeslagen.','6-character verification code'=>'6-tekens verificatiecode','Use a different email'=>'Een ander e-mailadres gebruiken','Username or email'=>'Gebruikersnaam of e-mailadres','Password'=>'Wachtwoord','Remember me'=>'Onthoud mij','Forgot password?'=>'Wachtwoord vergeten?','Use a magic link instead'=>'Gebruik in plaats daarvan een magische link','Send Reset Link'=>'Herstellink versturen','Back to sign in'=>'Terug naar inloggen','New password'=>'Nieuw wachtwoord','Confirm new password'=>'Bevestig nieuw wachtwoord','Save and sign in'=>'Opslaan en inloggen','Email address'=>'E-mailadres','Send Link'=>'Link versturen','Sign in with password'=>'Inloggen met wachtwoord','Change language. Current:'=>'Taal wijzigen. Huidig:']];